document.addEventListener('DOMContentLoaded', () => {
const hamburger = document.querySelector('.nav-hamburger');
const mobileMenu = document.querySelector('.nav-mobile');
if (hamburger && mobileMenu) {
function openMobileMenu() {
const navEl = document.querySelector('.site-nav');
if (navEl) mobileMenu.style.top = navEl.offsetHeight + 'px';
hamburger.classList.add('open');
mobileMenu.classList.add('open');
hamburger.setAttribute('aria-expanded', 'true');
document.body.style.overflow = 'hidden';
}
function closeMobileMenu() {
hamburger.classList.remove('open');
mobileMenu.classList.remove('open');
hamburger.setAttribute('aria-expanded', 'false');
document.body.style.overflow = '';
}
hamburger.addEventListener('click', () => {
mobileMenu.classList.contains('open') ? closeMobileMenu() : openMobileMenu();
});
mobileMenu.querySelectorAll('a').forEach(link => {
link.addEventListener('click', closeMobileMenu);
});
document.addEventListener('keydown', e => {
if (e.key === 'Escape' && mobileMenu.classList.contains('open')) closeMobileMenu();
});
}
document.querySelectorAll('.nav-item.has-dropdown').forEach(item => {
const trigger = item.querySelector('.nav-dropdown-trigger');
const dropdown = item.querySelector('.nav-dropdown');
if (!trigger || !dropdown) return;
trigger.addEventListener('click', (e) => {
e.stopPropagation();
const isOpen = item.classList.contains('open');
document.querySelectorAll('.nav-item.has-dropdown.open').forEach(other => {
if (other !== item) {
other.classList.remove('open');
other.querySelector('.nav-dropdown-trigger')?.setAttribute('aria-expanded', 'false');
}
});
item.classList.toggle('open', !isOpen);
trigger.setAttribute('aria-expanded', String(!isOpen));
});
item.addEventListener('keydown', (e) => {
if (e.key === 'Escape') {
item.classList.remove('open');
trigger.setAttribute('aria-expanded', 'false');
trigger.focus();
}
});
});
document.addEventListener('click', () => {
document.querySelectorAll('.nav-item.has-dropdown.open').forEach(item => {
item.classList.remove('open');
item.querySelector('.nav-dropdown-trigger')?.setAttribute('aria-expanded', 'false');
});
});
document.querySelectorAll('.mobile-nav-group-trigger').forEach(trigger => {
trigger.addEventListener('click', () => {
const group = trigger.closest('.mobile-nav-group');
const isOpen = group.classList.contains('open');
group.classList.toggle('open', !isOpen);
trigger.setAttribute('aria-expanded', String(!isOpen));
});
});
const currentPath = window.location.pathname.split('/').pop();
document.querySelectorAll('.nav-links a, .nav-mobile a').forEach(link => {
const href = link.getAttribute('href');
if (href && href === currentPath) link.classList.add('active');
if (!currentPath && href === 'index.html') link.classList.add('active');
});
const nav = document.querySelector('.site-nav');
if (nav) {
window.addEventListener('scroll', () => {
nav.classList.toggle('scrolled', window.scrollY > 40);
}, { passive: true });
}
document.querySelectorAll('.faq-question').forEach(question => {
question.addEventListener('click', () => {
const item = question.closest('.faq-item');
const isOpen = item.classList.contains('open');
const list = item.closest('.faq-list');
if (list) {
list.querySelectorAll('.faq-item.open').forEach(openItem => {
if (openItem !== item) openItem.classList.remove('open');
});
}
item.classList.toggle('open', !isOpen);
});
});
const animatedEls = document.querySelectorAll(
'.stat-card, .why-card, .offer-card, .step-item, .benefit-card'
);
if ('IntersectionObserver' in window) {
const observer = new IntersectionObserver((entries) => {
entries.forEach((entry, i) => {
if (entry.isIntersecting) {
setTimeout(() => {
entry.target.style.opacity = '1';
entry.target.style.transform = 'translateY(0)';
}, i * 80);
observer.unobserve(entry.target);
}
});
}, { threshold: 0.12 });
animatedEls.forEach(el => {
el.style.opacity = '0';
el.style.transform = 'translateY(20px)';
el.style.transition = 'opacity 0.5s ease, transform 0.5s ease';
observer.observe(el);
});
}
function animateCounter(el, target, suffix = '') {
const duration = 1500;
const start = performance.now();
const update = (time) => {
const elapsed = time - start;
const progress = Math.min(elapsed / duration, 1);
const eased = 1 - Math.pow(1 - progress, 3);
const current = Math.floor(target * eased);
el.textContent = current.toLocaleString('cs-CZ') + suffix;
if (progress < 1) requestAnimationFrame(update);
};
requestAnimationFrame(update);
}
const counterEls = document.querySelectorAll('[data-counter]');
if ('IntersectionObserver' in window && counterEls.length) {
const counterObserver = new IntersectionObserver((entries) => {
entries.forEach(entry => {
if (entry.isIntersecting) {
const el = entry.target;
animateCounter(el, parseInt(el.dataset.counter, 10), el.dataset.suffix || '');
counterObserver.unobserve(el);
}
});
}, { threshold: 0.5 });
counterEls.forEach(el => counterObserver.observe(el));
}
const yearEl = document.getElementById('footer-year');
if (yearEl) yearEl.textContent = new Date().getFullYear();
document.querySelectorAll('a[href="#"]').forEach(a => {
a.addEventListener('click', e => e.preventDefault());
});
document.querySelectorAll('a[href^="#"]').forEach(link => {
const href = link.getAttribute('href');
if (href === '#') return;
link.addEventListener('click', e => {
const target = document.querySelector(href);
if (target) {
e.preventDefault();
const navEl = document.querySelector('.site-nav');
const offset = navEl ? navEl.offsetHeight + 12 : 108;
window.scrollTo({ top: target.getBoundingClientRect().top + window.scrollY - offset, behavior: 'smooth' });
}
});
});
const reviewsCarousel = document.querySelector('.reviews-carousel');
if (reviewsCarousel) {
const reviewsTrack = reviewsCarousel.querySelector('.reviews-track');
const reviewsPrev = document.getElementById('reviews-prev');
const reviewsNext = document.getElementById('reviews-next');
const dotsContainer = document.getElementById('reviews-dots');
const reviewCards = Array.from(reviewsTrack.querySelectorAll('.review-card'));
let reviewsDots = [];
function getStep() {
const gap = parseFloat(getComputedStyle(reviewsTrack).gap) || 0;
const cardW = reviewCards[0] ? reviewCards[0].offsetWidth : 0;
return { cardW, gap, step: cardW + gap };
}
function buildDots() {
dotsContainer.innerHTML = '';
reviewsDots = [];
const { cardW, gap, step } = getStep();
const trackW = reviewsTrack.clientWidth;
const visible = cardW > 0 ? Math.max(1, Math.round((trackW + gap) / step)) : 1;
const dotCount = Math.max(1, reviewCards.length - visible + 1);
for (let i = 0; i < dotCount; i++) {
const dot = document.createElement('button');
dot.className = 'reviews-dot' + (i === 0 ? ' active' : '');
dot.setAttribute('aria-label', `Pozice ${i + 1}`);
const idx = i;
dot.addEventListener('click', () => {
const { step: s } = getStep();
reviewsTrack.scrollTo({ left: idx * s, behavior: 'smooth' });
});
dotsContainer.appendChild(dot);
reviewsDots.push(dot);
}
}
function updateReviewDots() {
if (!reviewsDots.length) return;
const { step } = getStep();
if (!step) return;
const closest = Math.min(
Math.round(reviewsTrack.scrollLeft / step),
reviewsDots.length - 1
);
reviewsDots.forEach((dot, i) => dot.classList.toggle('active', i === closest));
}
requestAnimationFrame(() => { buildDots(); updateReviewDots(); });
reviewsTrack.addEventListener('scroll', updateReviewDots, { passive: true });
let resizeTimer;
window.addEventListener('resize', () => {
clearTimeout(resizeTimer);
resizeTimer = setTimeout(() => { buildDots(); updateReviewDots(); }, 200);
});
function getReviewScrollAmount() {
const card = reviewCards[0];
if (!card) return reviewsTrack.offsetWidth / 4;
const gap = parseFloat(getComputedStyle(reviewsTrack).gap) || 0;
return card.offsetWidth + gap;
}
if (reviewsPrev) reviewsPrev.addEventListener('click', () => {
reviewsTrack.scrollBy({ left: -getReviewScrollAmount(), behavior: 'smooth' });
});
if (reviewsNext) reviewsNext.addEventListener('click', () => {
reviewsTrack.scrollBy({ left: getReviewScrollAmount(), behavior: 'smooth' });
});
}
const carousel = document.querySelector('.photo-carousel');
if (carousel) {
const track = carousel.querySelector('.carousel-track');
const slides = carousel.querySelectorAll('.carousel-slide');
const prevBtn = carousel.querySelector('.carousel-prev');
const nextBtn = carousel.querySelector('.carousel-next');
const dots = carousel.querySelectorAll('.carousel-dot');
let current = 0;
function goTo(index) {
current = (index + slides.length) % slides.length;
track.style.transform = `translateX(-${current * 100}%)`;
dots.forEach((d, i) => d.classList.toggle('active', i === current));
}
if (prevBtn) prevBtn.addEventListener('click', () => goTo(current - 1));
if (nextBtn) nextBtn.addEventListener('click', () => goTo(current + 1));
dots.forEach((dot, i) => dot.addEventListener('click', () => goTo(i)));
let autoplay = setInterval(() => goTo(current + 1), 4500);
carousel.addEventListener('mouseenter', () => clearInterval(autoplay));
carousel.addEventListener('mouseleave', () => { autoplay = setInterval(() => goTo(current + 1), 4500); });
let startX = 0;
carousel.addEventListener('touchstart', e => { startX = e.touches[0].clientX; }, { passive: true });
carousel.addEventListener('touchend', e => {
const diff = startX - e.changedTouches[0].clientX;
if (Math.abs(diff) > 40) goTo(current + (diff > 0 ? 1 : -1));
});
}
document.querySelectorAll('.contact-form input, .contact-form textarea').forEach(input => {
input.addEventListener('focus', () => input.parentElement.classList.add('focused'));
input.addEventListener('blur', () => input.parentElement.classList.remove('focused'));
});
const FORMSPREE_URL = 'https://formspree.io/f/xojzkvwv';
document.querySelectorAll('.contact-form, form[novalidate]').forEach(form => {
form.addEventListener('submit', async e => {
e.preventDefault();
const required = form.querySelectorAll('[required]');
let valid = true;
required.forEach(input => {
input.classList.remove('cfn-error');
if (!input.value.trim()) { input.classList.add('cfn-error'); valid = false; }
});
if (!valid) return;
const submitBtn = form.querySelector('[type="submit"]');
if (!submitBtn) return;
const originalText = submitBtn.textContent;
submitBtn.textContent = 'Odesílám…';
submitBtn.disabled = true;
try {
const res = await fetch(FORMSPREE_URL, {
method: 'POST',
body: new FormData(form),
headers: { 'Accept': 'application/json' }
});
if (res.ok) {
submitBtn.textContent = '✓ Odesláno! Ozveme se co nejdříve.';
submitBtn.style.background = 'var(--color-green-dark)';
form.querySelectorAll('input, textarea, select').forEach(el => { el.disabled = true; });
} else {
submitBtn.textContent = originalText;
submitBtn.disabled = false;
alert('Nepodařilo se odeslat zprávu. Zkuste to prosím znovu nebo nás kontaktujte přímo.');
}
} catch {
submitBtn.textContent = originalText;
submitBtn.disabled = false;
alert('Chyba připojení. Zkontrolujte internet a zkuste to znovu.');
}
});
});
});